function ensureActivity(turnId,root){let turn=state.activities.get(turnId);if(turn?.isConnected)return turn;turn=ensureTurnTimeline(turnId,root);const slot=turn.querySelector('.turn-activity-slot');if(!slot.querySelector('[data-agent-activity-group]')){slot.innerHTML=`<div class="activity-group active" data-agent-activity-group><button class="activity-summary open">${icons.chevron}<span class="activity-summary-copy loading-shimmer">Working</span></button><div class="activity-items open"></div></div>`;slot.querySelector('.activity-summary').onclick=(e)=>{const b=e.currentTarget,items=b.nextElementSibling;b.classList.toggle('open');items.classList.toggle('open')}}state.activities.set(turnId,turn);if(!state.activityItems.has(turnId))state.activityItems.set(turnId,new Map);return turn}
