function updateActivitySummary(turn){const turnId=turn.dataset.turnId,items=[...(state.activityItems.get(turnId)?.values()||[])],activity=turn.querySelector('[data-agent-activity-group]'),summary=activity?.querySelector('.activity-summary-copy');if(!activity||!summary)return;const activeItem=items.findLast?.(item=>summarizeActivity(item).active)||[...items].reverse().find(item=>summarizeActivity(item).active);if(activeItem){const data=summarizeActivity(activeItem);summary.textContent=data.label;summary.classList.add('loading-shimmer');activity.classList.add('active');activity.querySelector('.activity-summary').classList.add('open');activity.querySelector('.activity-items').classList.add('open')}else{summary.textContent=completedActivitySummary(items);summary.classList.remove('loading-shimmer');activity.classList.remove('active');activity.querySelector('.activity-summary').classList.remove('open');activity.querySelector('.activity-items').classList.remove('open')}syncWorkedForDivider(turnId)}
