function onNotification(method,p){
  if(method==='account/updated')loadAccount(true);
  else if(method==='thread/started'){state.threads.unshift(p.thread);renderThreads()}
  else if(method==='thread/name/updated'){const t=state.threads.find(x=>x.id===p.threadId);if(t)t.name=p.name;renderThreads();renderHeader()}
  else if(method==='turn/started'){$('#sendButton').dataset.turnId=p.turn?.id||'';$('#sendButton').classList.add('stop')}
  else if(method==='item/started'||method==='item/completed')upsertItem(p.item,p.turnId);
  else if(method==='item/agentMessage/delta'){let el=state.items.get(p.itemId);if(!el){upsertItem({id:p.itemId,type:'agentMessage',text:''},p.turnId);el=state.items.get(p.itemId)}const body=el.querySelector('.message-text');body.dataset.raw=(body.dataset.raw||'')+p.delta;body.innerHTML=renderAssistantMarkdown(body.dataset.raw);scrollBottom()}
  else if(method==='item/commandExecution/outputDelta'){const group=state.activities.get(p.turnId),row=group?.querySelector(`[data-item-id="${CSS.escape(p.itemId)}"]`);if(row){const out=row.nextElementSibling;out.textContent=(out.textContent||'')+(p.delta||'')}}
  else if(method==='turn/diff/updated'){if(p.threadId&&state.active?.id&&p.threadId!==state.active.id)return;const review=parseUnifiedDiff(p.diff||'');review.turnId=p.turnId;review.raw=p.diff||'';state.turnDiffs.set(p.turnId,review);state.activeReview=review;renderChanges()}
  else if(method==='turn/completed'){$('#sendButton').classList.remove('stop');$('#sendButton').dataset.turnId='';if(p.turn?.items)for(const i of p.turn.items)upsertItem(i,p.turn.id);if(p.turn?.id)syncWorkedForDivider(p.turn.id,turnDurationMs(p.turn));refreshThreadsSoon()}
  else if(method==='thread/tokenUsage/updated'){/* The current native composer does not render a persistent percentage ring. */}
  else if(method==='thread/status/changed')refreshThreadsSoon();
  else if(method==='error')toast(p.error?.message||p.message||'Codex error');
}
function setApprovalWaiting(group,itemId,waiting){if(!group)return;const row=itemId?group.querySelector(`[data-item-id="${CSS.escape(itemId)}"]`):null,summary=group.querySelector('.activity-summary-copy');group.classList.toggle('waiting-approval',waiting);if(waiting){summary.textContent='Waiting for approval';summary.classList.remove('loading-shimmer');if(row){row.querySelector('.activity-name')?.classList.remove('loading-shimmer');state.motion.get(row)?.pause()}}else{if(row){row.querySelector('.activity-name')?.classList.add('loading-shimmer');state.motion.get(row)?.play()}updateActivitySummary(group)}}
